mapper.select:
SELECT  WRKTM_ID
  FROM  TB_COMMUTE
 WHERE  EMPLYR_ID = #{emplyrId}
   AND  WRKT_DT = #{wrktDt}

mapper.insert:
INSERT  INTO TB_COMMUTE
      ( WRKTM_ID
      , EMPLYR_ID
      , ORGNZT_ID
      , WRKT_DT
      , WRK_START_TIME
      , WRK_START_STATUS
      , FRST_REGIST_PNTTM
      , FRST_REGISTER_ID )
VALUES  ( #{wrktmId}
        , #{emplyrId}
        , #{orgnztId}
        , #{wrktDt}
        , #{wrkStartTime}
        , #{wrkStartStatus}
        , CURRENT_TIMESTAMP
        , #{emplyrId} )

mapper.update:
UPDATE  TB_COMMUTE
   SET  WRK_END_TIME = #{wrkEndTime}
      , WRK_END_STATUS = #{wrkEndStatus}
      , WRK_HOURS = #{wrkHours}
      , OVTMWRK_HOURS = #{ovtmwrkHours}
      , LAST_UPDT_PNTTM = CURRENT_TIMESTAMP
      , LAST_UPDUSR_ID = #{emplyrId}
 WHERE  WRKTM_ID = #{wrktmId}
